 using System.ComponentModel;
 using System.Net.Http.Json;
 using System.Text.Json;
 using ModelContextProtocol.Server;

 [McpServerToolType]
 public static class WeatherTools
 {
     [McpServerTool(Name = "get_weather"),
      Description("Gets current weather for a location by latitude and longitude.")]
     public static async Task<string> GetWeather(
         IHttpClientFactory httpClientFactory,
         [Description("Latitude of the location")] double latitude,
         [Description("Longitude of the location")] double longitude)
     {
         using var client = httpClientFactory.CreateClient("WeatherApi");

         var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                 + "&current=temperature_2m,wind_speed_10m";

         using var response = await client.GetAsync(url);
         response.EnsureSuccessStatusCode();

         var json = await response.Content.ReadFromJsonAsync<JsonElement>();
         var current = json.GetProperty("current");

         var temp = current.GetProperty("temperature_2m").GetDouble();
         var wind = current.GetProperty("wind_speed_10m").GetDouble();

         return $"Temperature: {temp}°C, Wind: {wind} km/h";
     }

     [McpServerTool(Name = "get_forecast"),
      Description("Gets a multi-day weather forecast for a location.")]
     public static async Task<string> GetForecast(
         IHttpClientFactory httpClientFactory,
         [Description("Latitude of the location")] double latitude,
         [Description("Longitude of the location")] double longitude,
         [Description("Number of forecast days (1-7)")] int days = 3)
     {
         days = Math.Clamp(days, 1, 7);
         using var client = httpClientFactory.CreateClient("WeatherApi");

         var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                 + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

         using var response = await client.GetAsync(url);
         response.EnsureSuccessStatusCode();

         var json = await response.Content.ReadFromJsonAsync<JsonElement>();
         var daily = json.GetProperty("daily");

         var dates = daily.GetProperty("time").EnumerateArray();
         var maxTemps = daily.GetProperty("temperature_2m_max").EnumerateArray();
         var minTemps = daily.GetProperty("temperature_2m_min").EnumerateArray();

         var lines = dates.Zip(maxTemps.Zip(minTemps, (max, min) => (max, min)),
             (date, temps) =>
                 $"{date.GetString()}: {temps.min.GetDouble()}°C – {temps.max.GetDouble()}°C");

         return string.Join("\n", lines);
     }
 }

